// Универсальный обработчик: приводим message и callback_query к одному формату
const input = $input.first().json;

let result = {
  type: null,           // 'command', 'text', 'callback', 'photo', 'voice', 'document'
  text: null,           // что написал/нажал пользователь
  chat_id: null,        // куда отвечать
  user_id: null,        // ID пользователя (для будущей мультиучёткой)
  username: null,       // @username
  first_name: null,     // Имя
  message_id: null,     // ID сообщения (для редактирования)
  callback_query_id: null, // нужно для answerCallbackQuery
  raw: input            // сохраняем оригинал на всякий случай
};

// Если это нажатие на инлайн-кнопку
if (input.callback_query) {
  const cb = input.callback_query;
  result.type = 'callback';
  result.text = cb.data;                          // например "level_B1"
  result.chat_id = cb.message.chat.id;
  result.user_id = cb.from.id;
  result.username = cb.from.username || null;
  result.first_name = cb.from.first_name || '';
  result.message_id = cb.message.message_id;
  result.callback_query_id = cb.id;
}
// Если это обычное сообщение
else if (input.message) {
  const msg = input.message;
  result.chat_id = msg.chat.id;
  result.user_id = msg.from.id;
  result.username = msg.from.username || null;
  result.first_name = msg.from.first_name || '';
  result.message_id = msg.message_id;

  // Определяем тип контента
  if (msg.text && msg.text.startsWith('/')) {
    result.type = 'command';
    result.text = msg.text.split(' ')[0]; // только сама команда, без аргументов
  } else if (msg.text) {
    result.type = 'text';
    result.text = msg.text;
  } else if (msg.photo) {
    result.type = 'photo';
    result.text = msg.caption || '';
    // Telegram присылает массив photo размеров, последний — самый большой
    const largestPhoto = msg.photo[msg.photo.length - 1];
    result.photo_file_id = largestPhoto.file_id;
    result.caption = msg.caption || '';
  } else if (msg.voice) {
    result.type = 'voice';
    result.text = '';
  } else if (msg.document) {
    result.type = 'document';
    result.text = msg.caption || '';
  }
}

return [{ json: result }];

// Получаем всех учеников из предыдущего узла
const students = $input.all();

// Если учеников нет
if (students.length === 0) {
  return [{
    json: {
      message: "📭 У тебя пока нет учеников.\n\nДобавь первого командой /add_student"
    }
  }];
}

// Формируем красивый список
let text = `👥 *Твои ученики (${students.length}):*\n\n`;

students.forEach((item, index) => {
  const s = item.json;
  text += `${index + 1}. *${s.name}* (${s.age} лет)\n`;
  text += `   📊 Уровень: ${s.level}\n`;
  text += `   🎯 Цель: ${s.goal}\n`;
  text += `   📅 ${s.lesson_days} в ${s.lesson_time}\n`;
  text += `   💰 ${s.price_per_hour} тг/час\n\n`;
});

text += `_Чтобы добавить ещё одного — /add_student_`;

return [{
  json: {
    message: text
  }
}];

// Получаем данные из контекста
const userInput = ($('Normalize Input').first().json.text || '').trim();
const stateRow = $('Get Dialog State').first().json;
const userId = $('Normalize Input').first().json.user_id;
const chatId = $('Normalize Input').first().json.chat_id;

// Парсим уже собранные данные
let collected = {};
try {
  collected = typeof stateRow.collected_data === 'string' 
    ? JSON.parse(stateRow.collected_data || '{}')
    : (stateRow.collected_data || {});
} catch (e) {
  collected = {};
}

// Обработка команды отмены
if (userInput === '/cancel') {
  return [{
    json: {
      action: 'cancel',
      chat_id: chatId,
      user_id: userId,
      reply_text: '❌ Добавление ученика отменено.'
    }
  }];
}

// Валидация имени
if (userInput.length < 2 || userInput.length > 50) {
  return [{
    json: {
      action: 'invalid',
      chat_id: chatId,
      user_id: userId,
      reply_text: '⚠️ Имя должно быть от 2 до 50 символов. Попробуй ещё раз:'
    }
  }];
}

// Сохраняем имя
collected.name = userInput;

return [{
