const student = $('Find Student').first().json;
const topic = $('Parse Lesson Command').first().json.topic;
const chatId = $('Parse Lesson Command').first().json.chat_id;

// Определяем длительность урока примерно (60 минут стандарт)
const lessonDuration = 60;

// Системный промпт — задаём роль GPT
const systemPrompt = `Ты — опытный преподаватель английского языка с 10-летним стажем.
Ты создаёшь персонализированные планы уроков, учитывая возраст, уровень и интересы ученика.
Ты используешь современные методы обучения: коммуникативный подход, активное вовлечение, реальные жизненные ситуации.
Отвечай на русском языке (для учителя), но примеры и упражнения давай на английском.
Структурируй ответ через Markdown.`;

// Пользовательский промпт — описание задачи
const userPrompt = `Создай подробный план урока английского языка.

**Данные об ученике:**
- Имя: ${student.name}
- Возраст: ${student.age} лет
- Уровень CEFR: ${student.level}
- Цель обучения: ${student.goal}
- Интересы и хобби: ${student.interests}

**Параметры урока:**
- Тема: ${topic}
- Длительность: ${lessonDuration} минут
- Формат: индивидуальное занятие 1-на-1

**Требования к структуре урока:**

1. **🔥 Warm-up (5 минут)** — разговорная разминка по теме интересов ученика, плавно ведущая к теме урока

2. **📖 Объяснение темы (10-15 минут)** — теория с примерами. Адаптируй сложность под уровень ${student.level}. Используй темы из интересов ученика для примеров.

3. **✏️ Упражнения (20-25 минут)** — минимум 4 разнообразных упражнения по нарастающей сложности:
   - Заполнить пропуски
   - Переписать предложения
   - Перевод (русский → английский)
   - Создание собственных примеров
   Каждое упражнение должно содержать 4-6 пунктов с примерами и ответами.

4. **💬 Speaking practice (10-15 минут)** — задание на устную речь с использованием изученного материала, связанное с интересами ученика

5. **📝 Домашнее задание** — конкретное задание на 20-30 минут

6. **🎯 Цели урока** — что ученик должен освоить к концу

Сделай урок практичным, увлекательным и связанным с реальной жизнью ученика. Используй эмодзи для структурирования.`;

return [{
  json: {
    chat_id: chatId,
    student_name: student.name,
    student_level: student.level,
    topic: topic,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
}];

