// Универсальная функция извлечения текста из ответа OpenAI
function extractText(response) {
  // Структура 1: новый Responses API
  // { output: { content: [{ type: "output_text", text: "..." }] } }
  if (response.output?.content?.[0]?.text) {
    return response.output.content[0].text;
  }

  // Структура 2: новый Responses API с массивом output
  // { output: [{ content: [{ text: "..." }] }] }
  if (Array.isArray(response.output) && response.output[0]?.content?.[0]?.text) {
    return response.output[0].content[0].text;
  }

  // Структура 3: классический Chat Completions API
  // { choices: [{ message: { content: "..." } }] }
  if (response.choices?.[0]?.message?.content) {
    return response.choices[0].message.content;
  }

